import{_ as r,c as a,o,ag as s}from"./chunks/framework.XjE0kKti.js";const e="/gatewayweb/docs/assets/hub0021-overview.CJzw0AdJ.png",l="/gatewayweb/docs/assets/hub0021-instance-menu.BoBPHzAR.png",n="/gatewayweb/docs/assets/hub0021-route-edit.B8DYk4a1.png",i="/gatewayweb/docs/assets/hub0021-service-select.Duk5L6Qv.png",d="/gatewayweb/docs/assets/hub0021-route-row-menu.BZqeaihQ.png",q=JSON.parse('{"title":"路由管理","description":"","frontmatter":{},"headers":[],"relativePath":"modules/hub0021.md","filePath":"modules/hub0021.md","lastUpdated":1776841524000}'),h={name:"modules/hub0021.md"};function g(u,t,p,c,b,_){return o(),a("div",null,[...t[0]||(t[0]=[s('<h1 id="路由管理" tabindex="-1">路由管理 <a class="header-anchor" href="#路由管理" aria-label="Permalink to &quot;路由管理&quot;">​</a></h1><p>用于在指定<strong>网关实例</strong>下维护路由规则：定义如何匹配请求（路径、方法、优先级等），以及命中后关联的目标服务，并通过断言、过滤器与访问控制等能力完成治理。</p><p><img src="'+e+'" alt="路由管理：实例列表与路由列表"></p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>路由管理关注两件事：</p><ul><li><strong>请求如何命中</strong>：通过路由路径 + 匹配类型（精确/前缀/正则）+ HTTP 方法等规则匹配。</li><li><strong>命中后如何转发与治理</strong>：关联服务定义，并按需配置断言、过滤器、访问控制、跨域、认证、限流等。</li></ul><p>本模块为“实例维度”配置：左侧先选择网关实例，右侧只展示该实例下的路由配置。</p><hr><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><p>侧栏 <strong>网关管理</strong> → <strong>路由管理</strong>。</p><hr><h2 id="页面布局" tabindex="-1">页面布局 <a class="header-anchor" href="#页面布局" aria-label="Permalink to &quot;页面布局&quot;">​</a></h2><p>页面为左右分栏：</p><table tabindex="0"><thead><tr><th>区域</th><th>说明</th></tr></thead><tbody><tr><td>左侧</td><td><strong>网关实例列表</strong>：选择实例；支持过滤与刷新；并提供实例级的 <strong>Router配置</strong> 与 <strong>全局过滤器配置</strong> 入口。</td></tr><tr><td>右侧</td><td><strong>路由配置列表</strong>：对所选实例的路由进行查询、新增、编辑、删除，以及进入各类路由级治理配置。</td></tr></tbody></table><hr><h2 id="操作说明" tabindex="-1">操作说明 <a class="header-anchor" href="#操作说明" aria-label="Permalink to &quot;操作说明&quot;">​</a></h2><h3 id="_1-选择目标网关实例" tabindex="-1">1. 选择目标网关实例 <a class="header-anchor" href="#_1-选择目标网关实例" aria-label="Permalink to &quot;1. 选择目标网关实例&quot;">​</a></h3><p>在左侧 <strong>网关实例列表</strong> 中：</p><ul><li>可用搜索框按“实例名称、地址或端口”过滤。</li><li>单击某一实例后，右侧路由列表会切换为该实例的数据。</li></ul><p>实例节点右键菜单提供实例级入口（以当前版本为准）：</p><p><img src="'+l+'" alt="实例节点菜单：Router配置/全局过滤器配置"></p><ul><li><strong>Router配置</strong>：实例级 Router 参数（缓存、性能、错误处理等）。</li><li><strong>全局过滤器配置</strong>：实例级全局过滤器链路。</li></ul><p>说明：实例级配置通常作为“全局默认策略”；路由级配置用于对单条路由做更细粒度控制。</p><h3 id="_2-新增路由" tabindex="-1">2. 新增路由 <a class="header-anchor" href="#_2-新增路由" aria-label="Permalink to &quot;2. 新增路由&quot;">​</a></h3><p>在右侧点击 <strong>新增路由</strong>，填写基本信息：</p><ul><li><strong>路由名称</strong>：建议可读且可追踪（例如含业务域/环境）。</li><li><strong>路由路径</strong>：建议以 <code>/</code> 开头。</li><li><strong>匹配类型</strong>： <ul><li><strong>精确匹配</strong>：路径必须完全一致。</li><li><strong>前缀匹配</strong>：以指定前缀开头即可命中（常用于一组 API）。</li><li><strong>正则匹配</strong>：复杂匹配模式，建议审慎使用。</li></ul></li><li><strong>HTTP 方法</strong>：为空通常表示不限制（全部）。</li><li><strong>优先级</strong>：数值越小优先级越高；多条规则同时命中时，优先级更高的先匹配。</li><li><strong>关联服务</strong>：选择转发目标服务定义（来自代理模块的服务定义）。</li></ul><p><img src="'+n+'" alt="编辑路由配置：基本信息与关联服务"></p><p>选择关联服务时，会弹出服务选择窗口：</p><p><img src="'+i+'" alt="选择服务定义"></p><p>保存后，路由将出现在列表中。</p><h3 id="_3-编辑、查看与删除" tabindex="-1">3. 编辑、查看与删除 <a class="header-anchor" href="#_3-编辑、查看与删除" aria-label="Permalink to &quot;3. 编辑、查看与删除&quot;">​</a></h3><ul><li><strong>查看详情</strong>：只读核对字段。</li><li><strong>编辑</strong>：修改路由匹配规则、优先级、方法、关联服务等。</li><li><strong>删除</strong>：支持单条删除；工具栏也支持批量删除（需先勾选）。</li></ul><h3 id="_4-路由级治理配置-右键菜单" tabindex="-1">4. 路由级治理配置（右键菜单） <a class="header-anchor" href="#_4-路由级治理配置-右键菜单" aria-label="Permalink to &quot;4. 路由级治理配置（右键菜单）&quot;">​</a></h3><p>在路由行上右键，可进入路由级治理能力：</p><p><img src="'+d+'" alt="路由行菜单：路由配置子菜单"></p><p>常见入口说明：</p><ul><li><strong>路由断言配置</strong>：为路由增加额外匹配条件或校验逻辑。</li><li><strong>IP / User-Agent / API / 域名访问控制</strong>：对命中该路由的请求执行放行/拦截。</li><li><strong>跨域配置</strong>：配置 CORS 相关策略。</li><li><strong>认证配置</strong>：配置认证方式与参数（以界面为准）。</li><li><strong>限流配置</strong>：为路由设置限流策略与阈值（以界面为准）。</li><li><strong>路由过滤器</strong>：为单条路由配置过滤器链路（与实例级全局过滤器互补）。</li></ul><hr><h2 id="推荐配置顺序" tabindex="-1">推荐配置顺序 <a class="header-anchor" href="#推荐配置顺序" aria-label="Permalink to &quot;推荐配置顺序&quot;">​</a></h2><ol><li>在「代理管理（hub0022）」中创建好服务定义与节点。</li><li>在本页选择实例，新增路由并关联服务。</li><li>先用断言/访问控制把“该放行谁、拦截谁”定义清楚，再按需要加认证与限流。</li><li>变更后按实例发布策略重载/刷新（若需要）。</li></ol><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>可能原因与处理</th></tr></thead><tbody><tr><td>右侧列表为空</td><td>先确认左侧已选择实例；或筛选条件过严，尝试重置。</td></tr><tr><td>命中路由不符合预期</td><td>检查 <strong>匹配类型</strong>、<strong>路由路径</strong> 与 <strong>优先级</strong>（数值越小优先级越高）。</td></tr><tr><td>修改后未生效</td><td>可能需要按实例的发布策略执行重载/刷新；同时确认修改的是正确实例与正确路由。</td></tr><tr><td>关联服务后仍 502/连接失败</td><td>回到「代理管理（hub0022）」检查服务节点地址/协议/端口与健康状态。</td></tr></tbody></table>',44)])])}const P=r(h,[["render",g]]);export{q as __pageData,P as default};
